_SVG_OPEN = (
    '<svg class="{cls}" viewBox="0 0 24 24" fill="none" stroke="currentColor" '
    'stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">'
)


@register.simple_tag
def icon(name, cls="icon"):
    """Render an inline SVG icon by name; falls back to a neutral tag icon."""
    inner = ICONS.get(name) or ICONS["tag"]
    return mark_safe(_SVG_OPEN.format(cls=cls) + inner + "</svg>")
